'use client'

import { useCurrentAccount, useDAppKit } from '@mysten/dapp-kit-react'
import { Transaction } from '@mysten/sui/transactions'
import { clientConfig } from '@/config/clientConfig'

export const TokenTransfer = ({ objectId, recipient }: {
  objectId: string
  recipient: string
}) => {
  const currentAccount = useCurrentAccount()
  const dAppKit = useDAppKit()

  const handleTransfer = async () => {
    if (!currentAccount) return
    const tx = new Transaction()
    tx.transferObjects([tx.object(objectId)], recipient)
    await dAppKit.signAndExecuteTransaction({ transaction: tx, account: currentAccount })
  }

  return <button onClick={() => void handleTransfer()}>Transfer</button>
}

